def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = 2000 + (ratio - 2) * 1000
        elif ratio > 1:
            priorities[i] = 1500 + (ratio - 1) * 700
        else:
            score = 0
            for j in range(1, 10):
                term = ((-1) ** j) * (ratio ** j) / j
                if j % 2 == 0:
                    term *= 1.5
                else:
                    term *= 0.75
                score += term
            if capacity < item * 1.2:
                score *= 3
            elif capacity < item * 1.5:
                score *= 1.5
            else:
                for k in range(1, 4):
                    score += ((-1) ** k) * (ratio ** (k+10)) / (k+10)
            priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if np.isinf(priorities[i]):
            priorities[i] = max_priority + 200
    for i in range(len(priorities)):
        if priorities[i] < 0 and bins[i] % 2 == 0:
            priorities[i] *= 1.1
        elif priorities[i] < 0:
            priorities[i] *= 0.9
    return priorities
